def num_distinct(s: str, t: str) -> int:
    """Count distinct subsequences of s that equal t."""
    m = len(t)
    if m == 0:
        return 1
    if len(s) < m:
        return 0

    dp = [0] * (m + 1)
    dp[0] = 1

    for ch in s:
        for j in range(m - 1, -1, -1):
            if ch == t[j]:
                dp[j + 1] += dp[j]

    return dp[m]

