def num_distinct(s: str, t: str) -> int:
    """Count distinct subsequences of s that equal t."""
    m, n = len(t), len(s)
    if m > n:
        return 0
    dp = [0] * (m + 1)
    dp[0] = 1  # Base case: one way to form empty string
    for char in s:
        # Iterate backwards to avoid overwriting values needed for current iteration
        for j in range(m, 0, -1):
            if char == t[j - 1]:
                dp[j] += dp[j - 1]
    return dp[m]
